public static class OrderResultAssertions
{
    public static void AssertSuccessResult(this OrderResult result, string expectedStatus = "Processed")
    {
        Assert.IsTrue(result.Success, "Order should be successful");
        Assert.AreEqual(expectedStatus, result.Status, "Status should be " + expectedStatus);
    }

    public static void AssertFailedResult(this OrderResult result, string expectedStatus)
    {
        Assert.IsFalse(result.Success, "Order should have failed");
        Assert.AreEqual(expectedStatus, result.Status, $"Status should be {expectedStatus}");
    }

    public static void AssertTotalAmount(this OrderResult result, decimal expectedTotal)
    {
        Assert.AreEqual(expectedTotal, result.Total, $"Total should be {expectedTotal}");
    }
}

public static class ValidationResultAssertions
{
    public static void AssertValidationPassed(this ValidationResult result)
    {
        Assert.IsTrue(result.IsValid, "Validation should pass");
    }

    public static void AssertValidationFailed(this ValidationResult result, string expectedMessage)
    {
        Assert.IsFalse(result.IsValid, "Validation should fail");
        Assert.AreEqual(expectedMessage, result.ErrorMessage, $"Message should be '{expectedMessage}'");
    }
}
