```csharp
[TestClass]
public sealed class OrderValidationTests
{
    private OrderValidator _validator;

    [TestInitialize]
    public void Setup()
    {
        _validator = new OrderValidator();
    }

    [TestMethod]
    [DataRow("C001", "alice@example.com", new[] { 2 }, true, null)]
    [DataRow("C002", null, new[] { 1 }, false, "Email is required")]
    [DataRow("C003", "carol@example.com", new int[0], false, "Order must have items")]
    [DataRow("C004", "dave@example.com", new[] { 1 }, false, "Price must be positive")]
    [DataRow("C005", "eve@example.com", new[] { 1 }, false, "Quantity must be positive")]
    public void Validate_VariousScenarios(
        string customerId, 
        string email, 
        int[] quantities, 
        bool shouldBeValid, 
        string expectedError)
    {
        var order = BuildOrder(customerId, email, quantities);
        var result = _validator.Validate(order);

        if (shouldBeValid)
        {
            result.AssertValidationPassed();
        }
        else
        {
            result.AssertValidationFailed(expectedError);
        }
    }

    private Order BuildOrder(string customerId, string email, int[] quantities)
    {
        var items = quantities.Length == 0 
            ? new List<OrderItem>() 
            : quantities.Select(q => new OrderItemBuilder().WithQuantity(q).Build()).ToList();

        return OrderBuilder.Create()
            .WithCustomerId(customerId)
            .WithCustomerEmail(email)
            .WithItems(items.ToArray())
            .Build();
    }
}
```

